async function createVectorStore(config) {
  const logger2 = createLogger({ level: env.CIPHER_LOG_LEVEL });
  logger2.debug(`${LOG_PREFIXES.FACTORY} Creating vector storage system`, {
    type: config.type,
    collection: config.collectionName,
    dimension: config.dimension
  });
  const manager = new VectorStoreManager(config);
  try {
    const store = await manager.connect();
    logger2.info(`${LOG_PREFIXES.FACTORY} Vector storage system created successfully`, {
      type: manager.getInfo().backend.type,
      collection: config.collectionName,
      connected: manager.isConnected()
    });
    return { manager, store };
  } catch (error) {
    await manager.disconnect().catch(() => {
    });
    logger2.error(`${LOG_PREFIXES.FACTORY} Failed to create vector storage system`, {
      error: error instanceof Error ? error.message : String(error)
    });
    throw error;
  }
}
async function createDefaultVectorStore(collectionName = "knowledge_memory", dimension = 1536) {
  return createVectorStore({
    type: "in-memory",
    collectionName,
    dimension,
    maxVectors: 1e4
  });
}
